sql:
SELECT segment_description
FROM loan_segments
WHERE percentage_of_defaults = (
    SELECT MAX(percentage_of_defaults) FROM loan_segments
);

SELECT segment_id, total_loans
FROM loan_segments
ORDER BY total_loans DESC;

SELECT total_loans AS total_segment_loans
FROM loan_segments
WHERE segment_id = 1;

SELECT credit_score_range
FROM loan_segments
WHERE percentage_of_defaults = (
    SELECT MAX(percentage_of_defaults)
    FROM loan_segments
);

SELECT credit_score_range, AVG(total_loans) AS average_total_loans
FROM loan_segments
GROUP BY credit_score_range;

external_knowledge:
; A loan segment can be thought of as a group of loans with similar characteristics; 
; A risk score is a numerical value that represents the likelihood of a loan defaulting; 
; The maximum risk rank represents the highest ranked loan within a segment based on its risk score.

